package sample;

public class Str {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		String s="hello";
		
		System.out.println(s.length());
		
		String S1="Hello";
		
		System.out.println(s.equals(S1));
		
		System.out.println(s.equalsIgnoreCase(S1));
		
		System.out.println(s.toUpperCase());
		
		
	}

}
